insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('business:5-1-role-of-finance-function:mcq:ad590b1d', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'mcq', 'mcq', 1, '{"question": "A sole trader who wants to expand their business but cannot raise enough finance on their own might change the legal structure to:", "options": ["A franchise", "A partnership", "A charity", "A cooperative"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. By taking on a partner who can contribute capital, the sole trader gains access to more finance. The business becomes a partnership. They might later become a private limited company (Ltd) to sell shares for even more funding."}'::jsonb),
('business:5-1-role-of-finance-function:mcq:ddb78e2e', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'mcq', 'mcq', 1, '{"question": "Which of the following best describes ''break-even''?", "options": ["The point at which a business starts to make a large profit", "The number of units a business must sell to cover all its costs", "The total amount of money coming into a business from sales", "The difference between a business''s revenue and its fixed costs"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Break-even is the output level at which total revenue equals total costs — meaning the business makes neither a profit nor a loss. It tells managers the minimum sales needed to avoid a financial loss."}'::jsonb),
('business:5-1-role-of-finance-function:tf:bb0dcaab', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'tf', 'tf', 1, '{"question": "The finance function is only found in small businesses such as sole traders."}'::jsonb, '{"answer": false, "explain": "FALSE. The finance function (finance department) is only found in LARGER businesses. Sole traders and partnerships usually employ an external accountant to manage their finances instead."}'::jsonb),
('business:5-1-role-of-finance-function:tf:1b34ba32', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'tf', 'tf', 1, '{"question": "Break-even is the point at which a business''s total revenue equals its total costs."}'::jsonb, '{"answer": true, "explain": "TRUE. At the break-even point, the business is making neither a profit nor a loss. Every unit sold beyond break-even contributes to profit."}'::jsonb),
('business:5-1-role-of-finance-function:tf:251504f0', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'tf', 'tf', 1, '{"question": "The finance function is responsible for deciding on the style of a television advertisement."}'::jsonb, '{"answer": false, "explain": "FALSE. Designing and deciding on advertising is a marketing function. The finance function may set the advertising budget and monitor whether the campaign was profitable, but it does not create the advert."}'::jsonb),
('business:5-1-role-of-finance-function:tf:e6656be4', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'tf', 'tf', 1, '{"question": "A business that cannot raise finance may be unable to expand."}'::jsonb, '{"answer": true, "explain": "TRUE. Many small businesses remain small precisely because they could not raise the capital needed to grow. Finance is a key enabler of business growth."}'::jsonb),
('business:5-1-role-of-finance-function:tf:103bc6d0', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'tf', 'tf', 1, '{"question": "Cash flow records the inflow and outflow of money in a business."}'::jsonb, '{"answer": true, "explain": "TRUE. Cash flow tracks money coming in (inflows) and money going out (outflows). A cash-flow forecast helps a business spot future periods where it may not have enough cash to pay its bills."}'::jsonb),
('business:5-1-role-of-finance-function:tf:399edf39', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'tf', 'tf', 1, '{"question": "A sole trader who wants to raise more capital might convert their business into a partnership."}'::jsonb, '{"answer": true, "explain": "TRUE. By bringing in a partner who provides capital, the sole trader gains access to more finance. The business legally becomes a partnership, sharing ownership and responsibility."}'::jsonb),
('business:5-1-role-of-finance-function:tf:bf0547b8', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'tf', 'tf', 1, '{"question": "The finance function stands alone and does not interact with other departments."}'::jsonb, '{"answer": false, "explain": "FALSE. The finance function is deeply interdependent with all other departments. Marketing, operations, and HR all rely on financial data from the finance function to make decisions."}'::jsonb),
('business:5-1-role-of-finance-function:tf:2bc3e218', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'tf', 'tf', 1, '{"question": "Revenue is calculated by subtracting total costs from total profit."}'::jsonb, '{"answer": false, "explain": "FALSE. This is the wrong formula. Profit = Revenue − Costs. Revenue is the money received from sales; you cannot calculate it by subtracting costs from profit."}'::jsonb),
('business:5-1-role-of-finance-function:tf:657bbf4f', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'tf', 'tf', 1, '{"question": "Providing financial data on a business''s energy usage would be a task for the finance function."}'::jsonb, '{"answer": true, "explain": "TRUE. Tracking and reporting on costs — including energy costs — is part of the finance function''s role. This data helps management understand expenditure and make cost-saving decisions."}'::jsonb),
('business:5-1-role-of-finance-function:tf:8a2701f8', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'tf', 'tf', 1, '{"question": "Advertising price reductions to customers is a task performed by the finance function."}'::jsonb, '{"answer": false, "explain": "FALSE. Advertising is a marketing function. The finance team might set the budget for an advertising campaign, but the actual advertising activity belongs to marketing."}'::jsonb),
('business:5-1-role-of-finance-function:tf:44813437', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'tf', 'tf', 1, '{"question": "A public limited company (plc) can raise more finance than a sole trader because it can sell shares publicly on the stock market."}'::jsonb, '{"answer": true, "explain": "TRUE. A plc has access to the widest range of investors because its shares are traded publicly. This is one of the main reasons businesses change their legal form as they grow."}'::jsonb),
('business:5-1-role-of-finance-function:tf:6631f9f7', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'tf', 'tf', 1, '{"question": "The finance function is not involved when a business decides to become more environmentally friendly."}'::jsonb, '{"answer": false, "explain": "FALSE. Any change to business practice affects costs and cash flow. The finance function must calculate the extra costs of going green, assess the impact on break-even, and may need to arrange additional finance to fund the changes."}'::jsonb),
('business:5-1-role-of-finance-function:learn:45b3c21c', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>These are the essential terms you must know for this topic. Learn them precisely — examiners reward specific, accurate vocabulary.</p>\n<ul>\n  <li><strong>Finance Function:</strong> The department within a business (also called the finance department) responsible for managing money. Only found in larger businesses — small businesses usually employ an external accountant instead.</li>\n  <li><strong>Financial Information:</strong> Data including profit, loss, cash flow, break-even, profit margin, and average rate of return. Used to support business decision-making.</li>\n  <li><strong>Revenue:</strong> The money a business receives from selling goods or services.</li>\n  <li><strong>Costs:</strong> The expenses involved in making and selling a good or service.</li>\n  <li><strong>Profit/Loss:</strong> Found by subtracting total costs from total revenue. If revenue > costs = profit; if costs > revenue = loss.</li>\n  <li><strong>Break-Even:</strong> The number of products a business must sell to cover all its costs — neither making a profit nor a loss.</li>\n  <li><strong>Cash Flow:</strong> The movement of money into (inflows) and out of (outflows) a business over time.</li>\n  <li><strong>Forecast:</strong> An estimate or prediction of what is expected to happen in the future (e.g. a cash-flow forecast).</li>\n  <li><strong>Sources of Finance:</strong> Where a business gets money from — examples include savings, loans, overdrafts, and share issues.</li>\n  <li><strong>Interdependence:</strong> The way in which different departments within a business rely on each other to operate effectively.</li>\n</ul>", "question": "According to the key definitions, what is the ''finance function''?", "options": ["The department in a larger business that manufactures goods and inspects finished products", "The department in a larger business that manages money and produces financial information", "The department in a larger business that designs adverts and researches target customers", "The department in a larger business that recruits staff and organises training programmes"]}'::jsonb, '{"answer": 1, "explain": "The card defines the finance function as the department that manages money and produces financial information — distinct from HR, marketing, or production departments."}'::jsonb),
('business:5-1-role-of-finance-function:learn:37ec2a53', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'learn', 'mcq', 1, '{"readingTitle": "The Purpose of the Finance Function", "reading": "<p>The finance function exists to serve the whole business. Its two core purposes are:</p>\n<ul>\n  <li><strong>Supporting business planning and decision-making:</strong> The finance function contributes to the business plan and ensures all decisions are backed by accurate financial data.</li>\n  <li><strong>Providing financial information:</strong> It produces data on costs, revenues, profit/loss, cash flow, and break-even that other departments rely on to operate.</li>\n</ul>\n<p>Without reliable financial information, a business cannot plan effectively, cannot raise the funding it needs, and may make costly mistakes. As the textbook states: <em>it is vital for any business that this data is accurate and up to date.</em></p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Large Businesses</div>\n    <div class=\"pro-item\"><strong>Dedicated team:</strong> Have their own finance department with specialist staff (e.g. accountants, financial analysts).</div>\n    <div class=\"pro-item\"><strong>In-house expertise:</strong> Can respond quickly to financial questions from other departments.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Small Businesses</div>\n    <div class=\"con-item\"><strong>No finance department:</strong> Sole traders and partnerships usually hire an external accountant to check their finances.</div>\n    <div class=\"con-item\"><strong>Limited resources:</strong> Cannot afford a full-time specialist finance team, which may slow decision-making.</div>\n  </div>\n</div>", "question": "What are the two core purposes of the finance function described in this card?", "options": ["Recruiting new employees and organising staff appraisal and training programmes", "Negotiating supplier contracts and managing the delivery of essential raw materials", "Supporting business planning and providing financial information to other departments", "Designing new products and setting prices for the firm''s target market segments"]}'::jsonb, '{"answer": 2, "explain": "The card states the finance function exists to support business planning/decision-making and to provide financial information — not product design, recruitment, or supply-chain tasks."}'::jsonb),
('business:5-1-role-of-finance-function:learn:e1e9cc5f', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'learn', 'mcq', 1, '{"readingTitle": "Roles of the Finance Function", "reading": "<p>The finance function carries out a wide range of tasks to keep a business financially healthy. These include:</p>\n<ul>\n  <li><strong>Calculating sales revenues and production costs:</strong> Ensures the business knows exactly how much it earns and spends.</li>\n  <li><strong>Calculating profit or loss:</strong> Tells managers whether the business is financially viable.</li>\n  <li><strong>Forecasting cash flow:</strong> Uses expected revenues and expenditures to predict whether extra finance will be needed at any point.</li>\n  <li><strong>Calculating the break-even output:</strong> Identifies how many units must be sold to avoid a loss — essential for pricing and production decisions.</li>\n  <li><strong>Calculating the average rate of return:</strong> Measures how well an investment is performing over time.</li>\n  <li><strong>Arranging finance:</strong> Sources funding such as loans, overdrafts, or share issues when the business needs capital.</li>\n  <li><strong>Managing payments and receipts:</strong> Ensures bills are paid on time and money owed to the business is collected.</li>\n</ul>\n<p>⚠️ <strong>Examiner Warning:</strong> The finance function does NOT advertise products, recruit staff, make quality decisions, or choose marketing methods. These belong to other departments. Confusing these is a very common mistake.</p>", "question": "Which of these is listed as a role of the finance function, rather than another department?", "options": ["Calculating the break-even output needed to avoid making a loss", "Checking that finished goods meet the required quality standard", "Deciding which candidates should be shortlisted for interview", "Choosing which television advert style will attract more customers"]}'::jsonb, '{"answer": 0, "explain": "The card lists calculating break-even output as a finance function task; advertising style, recruitment shortlisting and quality checks belong to marketing, HR and operations instead."}'::jsonb),
('business:5-1-role-of-finance-function:learn:8fffd406', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'learn', 'mcq', 1, '{"readingTitle": "How the Finance Function Influences Business Activity", "reading": "<p>The finance function does not just record numbers — it actively shapes what the business can and cannot do. Here are key examples:</p>\n<ul>\n  <li><strong>Going environmentally friendly:</strong> The finance function calculates the extra costs involved, monitors cash flow, and may need to arrange additional finance to fund the changes.</li>\n  <li><strong>Responding to a recession:</strong> Provides revenue and cost data to help the business decide how to cut costs or protect cash flow.</li>\n  <li><strong>Changing production methods (e.g. job to flow):</strong> Forecasts changes in revenue, costs, and cash flow, and calculates the new break-even output.</li>\n  <li><strong>Running a marketing campaign:</strong> Sets a budget and monitors sales and profit data during and after the campaign to judge whether it was successful.</li>\n  <li><strong>Business expansion:</strong> Advises on sources of finance, forecasts costs, and models the impact on break-even and cash flow.</li>\n  <li><strong>Changing the way products are sold (e.g. moving online):</strong> Provides data on the impact of different sales channels on revenues and costs.</li>\n</ul>\n<p>This shows that business departments are <strong>interdependent</strong> — they rely on each other. The finance function sits at the heart of this, providing data that every other department needs to make good decisions.</p>", "question": "How does the finance function support a business that is changing its production method?", "options": ["It forecasts changes in revenue and costs and recalculates the new break-even output", "It writes the new job descriptions needed for the fully redesigned production process", "It negotiates the planning permission needed for the new production site", "It designs the new packaging that will be used once production has changed"]}'::jsonb, '{"answer": 0, "explain": "The card explains that when production methods change, finance forecasts revenue/cost changes and recalculates break-even — not job design, packaging, or planning permission."}'::jsonb),
('business:5-1-role-of-finance-function:learn:9f503461', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'learn', 'mcq', 1, '{"readingTitle": "Finance and Business Growth", "reading": "<p>The ability (or inability) to raise finance has a direct effect on how a business grows and what legal form it takes.</p>\n<ul>\n  <li><strong>Sole trader &rarr; Partnership:</strong> A sole trader who wants to expand may invite someone who can provide capital to become a partner.</li>\n  <li><strong>Partnership &rarr; Private Limited Company (Ltd):</strong> Partnerships may incorporate as a private limited company so they can sell shares and expand ownership.</li>\n  <li><strong>Private Limited Company &rarr; Public Limited Company (plc):</strong> A plc can sell shares publicly (on the stock market), gaining access to a much wider pool of investors.</li>\n</ul>\n<p>Many small businesses <strong>remain small</strong> simply because they could not raise the finance needed to expand. This shows how critically the finance function — or the lack of one — can shape the future of a business.</p>\n<div class=\"case-study-box\">\n  <h4>Case Study: Stellantis / Vauxhall — Ellesmere Port</h4>\n  <p>In July 2021, Stellantis (owners of Vauxhall) announced their Ellesmere Port factory would produce all-electric vans. The decision followed lengthy negotiations with the UK government, which reportedly offered a £30 million grant. The finance function at Stellantis played a central role — supporting business planning and ensuring all decision-making was informed by accurate financial data. Without this financial analysis, such a major investment decision could not have been made confidently.</p>\n  <p><strong>Takeaway:</strong> Large-scale business decisions always involve the finance function. It provides the financial evidence needed to justify investment, expansion, or change.</p>\n</div>", "question": "According to this card, why do many small businesses remain small?", "options": ["They lacked enough staff willing to work extra hours during busy periods", "They chose not to advertise their products outside their local area", "They could not raise the finance needed to expand into a larger business", "They refused to change their opening hours to suit more customers"]}'::jsonb, '{"answer": 2, "explain": "The card states many small businesses remain small simply because they could not raise the finance needed to expand — a direct link between finance and business growth."}'::jsonb),
('business:5-1-role-of-finance-function:learn:1fb1fe18', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'learn', 'mcq', 1, '{"readingTitle": "Financial Information: What It Includes", "reading": "<p>The finance function produces specific types of financial information. You need to know what each one is and why it matters:</p>\n<ul>\n  <li><strong>Sources of Finance (Unit 5.2):</strong> Where does the money come from? Savings, loans, overdrafts, share issues. Needed when the business wants to invest or expand.</li>\n  <li><strong>Revenue, Costs & Profit/Loss (Unit 5.3):</strong> Revenue − Total Costs = Profit or Loss. Tells managers whether the business is making money.</li>\n  <li><strong>Break-Even (Unit 5.4):</strong> How many units must be sold to cover all costs? Based on selling price and costs. Vital for setting prices and production targets.</li>\n  <li><strong>Cash Flow (Unit 5.5):</strong> Tracks money in and money out. Allows the business to spot periods where it may struggle to pay bills and plan ahead.</li>\n</ul>\n<div class=\"formula-box\">\n  <strong>Profit / Loss =</strong> Total Revenue &minus; Total Costs\n</div>\n<div class=\"formula-box\">\n  <strong>Break-Even Output =</strong> Fixed Costs &divide; (Selling Price &minus; Variable Cost per Unit)\n</div>\n<p>Each of these pieces of information feeds into business decision-making — no manager should make a significant decision without consulting the finance function first.</p>", "question": "Which of these is one of the four types of financial information listed in this card?", "options": ["Market map, which shows how competitors are positioned by price", "Break-even, which shows how many units must be sold to cover all costs", "Organisation chart, which shows the levels of hierarchy in a firm", "Job description, which shows the duties expected of a new employee"]}'::jsonb, '{"answer": 1, "explain": "The card lists break-even alongside sources of finance, revenue/costs/profit and cash flow as the four types of financial information — the other options belong to HR and marketing."}'::jsonb),
('business:5-1-role-of-finance-function:learn:82ce3f6c', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'learn', 'mcq', 1, '{"readingTitle": "Finance & Interdependence Between Departments", "reading": "<p>The finance function does not work in isolation. It is deeply connected to every other part of the business. This is called <strong>interdependence</strong>.</p>\n<ul>\n  <li><strong>Marketing:</strong> Finance sets marketing budgets and assesses whether a campaign generated enough extra revenue to justify its cost.</li>\n  <li><strong>Operations/Production:</strong> Finance provides data on production costs and calculates break-even when production methods change.</li>\n  <li><strong>Human Resources:</strong> Finance must approve wage increases, training budgets, and redundancy packages — all of which affect costs.</li>\n  <li><strong>Senior Management:</strong> Finance supplies the data that directors use to make strategic decisions about the future direction of the business.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: IKEA — Lancing Store Decision</h4>\n  <p>In July 2021, IKEA backed out of opening a new store at Lancing, West Sussex — a site it had identified back in 2016. The coronavirus pandemic had dramatically shifted consumer behaviour towards online shopping, making the financial case for the store much weaker. The finance function would have analysed projected revenues, costs, and profitability of the Lancing store before recommending the business not proceed. IKEA announced it would instead invest further in its online operations.</p>\n  <p><strong>Takeaway:</strong> The finance function doesn''t just track money — it protects the business from bad investments by providing the evidence needed to make the right call, even when that means walking away from a major project.</p>\n</div>", "question": "What does ''interdependence'' mean in the context of the finance function?", "options": ["Departments work in complete isolation without needing any shared data", "Different departments within a business rely on each other to operate effectively", "A business relies entirely on a single supplier for all of its raw material needs", "A company depends on a single bank for every one of its sources of finance"]}'::jsonb, '{"answer": 1, "explain": "The card defines interdependence as departments relying on each other — e.g. marketing depends on finance for a budget — which is the opposite of departments working in isolation."}'::jsonb),
('business:5-1-role-of-finance-function:misc:1c8921ad', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The finance function manages the whole business — it is the most important department.</p><p><strong>✅ The correct idea:</strong> The finance function is one of several departments. It provides financial information and supports other departments, but decisions are made across the business collaboratively. Its importance varies depending on the decision being made.</p>", "question": "Why is it wrong to say the finance function is ''the most important department''?", "options": ["It is one of several departments that provides data to support decisions made across the business", "It is actually the least important department of all because it only ever counts and records money", "It only really matters once a business is preparing to close down completely", "It is only relevant once a business has already become a public limited company"]}'::jsonb, '{"answer": 0, "explain": "The correct explanation is that finance is one of several interdependent departments supporting decisions collaboratively — its importance is not fixed as ''most important'' in every case."}'::jsonb),
('business:5-1-role-of-finance-function:misc:eaa0e5d4', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Revenue and profit are the same thing.</p><p><strong>✅ The correct idea:</strong> Revenue is the total money received from sales. Profit is what is LEFT after subtracting total costs from revenue. A business can have high revenue but still make a loss if its costs are even higher.</p>", "question": "What is the key difference between revenue and profit?", "options": ["Profit is always a fixed percentage of whatever revenue a business earns", "Profit is what remains after total costs are subtracted from total revenue", "Revenue is what remains after total costs are subtracted from total profit", "Revenue and profit both refer to the same figure shown on a cash-flow forecast"]}'::jsonb, '{"answer": 1, "explain": "Profit = Revenue − Costs, so profit is what is left after costs are deducted from revenue; a business can have high revenue but still make a loss if costs are higher still."}'::jsonb),
('business:5-1-role-of-finance-function:misc:88fa8755', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The finance function decides what to spend money on.</p><p><strong>✅ The correct idea:</strong> The finance function provides the financial data that informs spending decisions — but it does not make those decisions alone. For example, marketing decides to run a campaign; finance tells them how much they can afford and monitors the results.</p>", "question": "What role does the finance function actually play in spending decisions?", "options": ["It only gets involved after money has already been spent by a department", "It provides financial data that informs decisions but does not make them alone", "It makes every spending decision alone without input from other departments", "It has no involvement at all in decisions about how money is spent"]}'::jsonb, '{"answer": 1, "explain": "The correct view is that finance supplies the data — e.g. telling marketing what it can afford — while other departments still make the actual spending decision."}'::jsonb),
('business:5-1-role-of-finance-function:misc:65d793e3', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Break-even means the business is making a profit.</p><p><strong>✅ The correct idea:</strong> Break-even means the business is making exactly zero profit — it has covered all its costs but has nothing left over. Profit only begins after the break-even point is exceeded.</p>", "question": "What does reaching the break-even point actually mean for a business?", "options": ["The business has started to generate a small but growing profit", "The business has covered all its costs but made exactly zero profit", "The business has generated enough revenue to repay all its loans", "The business has made a loss equal to its total fixed costs"]}'::jsonb, '{"answer": 1, "explain": "Break-even means total revenue equals total costs, so the business makes exactly zero profit — profit only begins once output rises beyond the break-even point."}'::jsonb),
('business:5-1-role-of-finance-function:misc:f1bd230e', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Only large businesses need to worry about finance.</p><p><strong>✅ The correct idea:</strong> All businesses — no matter their size — must manage their finances well to survive. Small businesses may not have a finance department, but the owner must still track costs, revenue, and cash flow carefully.</p>", "question": "Which statement correctly describes who needs to manage finances carefully?", "options": ["Only businesses that sell shares publicly on the stock market need to worry", "Only large businesses with a dedicated finance department need to worry at all", "All businesses, regardless of size, must manage their finances well to survive", "Only businesses that have already taken out a large bank loan need to worry"]}'::jsonb, '{"answer": 2, "explain": "The card corrects the misconception that only large firms need to worry about finance — every business, including sole traders without a finance department, must track money carefully."}'::jsonb),
('business:5-1-role-of-finance-function:misc:392862a6', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ''Finance'' and ''finance function'' mean the same thing in exam questions.</p><p><strong>✅ The correct idea:</strong> In exam questions, ''finance'' often refers to money or sources of funding, while ''finance function'' refers to the specific department in a business. Read the question carefully to understand which one is being asked about.</p>", "question": "In exam questions, how do ''finance'' and ''finance function'' typically differ?", "options": ["''Finance'' always means a bank loan, while ''finance function'' means a share issue", "''Finance'' usually means money or funding, while ''finance function'' means the department", "''Finance'' and ''finance function'' are simply two names for the exact same department", "''Finance'' refers to profit only, while ''finance function'' refers to revenue only"]}'::jsonb, '{"answer": 1, "explain": "The card explains that ''finance'' often refers to money/funding, while ''finance function'' refers specifically to the department — so exam questions must be read carefully to see which is meant."}'::jsonb),
('business:5-1-role-of-finance-function:misc:3456e63d', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Saying ''the finance function manages the business efficiently'' is enough to score the understanding mark in an analyse question.</p><p><strong>✅ The correct idea:</strong> This is a tautological answer — it just repeats the idea without explaining what the finance function actually does. You must explain a specific task (e.g. producing cash-flow forecasts, calculating break-even) to earn the understanding mark.</p>", "question": "Why does saying the finance function ''manages the business efficiently'' fail to earn the understanding mark?", "options": ["It is factually incorrect because the finance function does not manage efficiency", "It is too technical for an examiner to accept as a valid business term", "It only applies to public limited companies, not to smaller private firms", "It is tautological and does not name a specific finance task the department performs"]}'::jsonb, '{"answer": 3, "explain": "The card explains this answer just repeats the idea without naming a specific task, such as producing cash-flow forecasts — a tautological answer scores no understanding mark."}'::jsonb),
('business:5-1-role-of-finance-function:misc:a971bde2', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Cash flow and profit are the same — if a business is profitable, it won''t have cash flow problems.</p><p><strong>✅ The correct idea:</strong> A profitable business can still run out of cash if it doesn''t receive payment from customers quickly enough. Cash flow is about timing of money in and out; profit is a longer-term calculation. A business can be profitable but cash-poor.</p>", "question": "Why can a profitable business still run into cash-flow problems?", "options": ["Profit and cash flow are identical figures calculated the same way", "A profitable business automatically receives all customer payments instantly", "Cash flow depends on payment timing, while profit is a longer-term calculation", "Cash-flow problems can only happen to a business that is making a loss"]}'::jsonb, '{"answer": 2, "explain": "The card explains that cash flow is about the timing of money in and out, whereas profit is a longer-term measure — so a business can be profitable yet still cash-poor."}'::jsonb),
('business:5-1-role-of-finance-function:tips:b87df807', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'tips', 'mcq', 1, '{"readingTitle": "Identify / State — 1 mark — One Point. Full Stop. Move On.", "reading": "\n      <p>A 1-mark <strong>''State'' or ''Identify''</strong> question needs exactly one correct, specific point. No explanation. No examples. No paragraphs.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li>One clear, specific finance function task = 1 mark ✅</li>\n        <li>A vague or general statement = 0 marks ❌</li>\n      </ul>\n      <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n      <em>\"The finance function manages money.\"</em><br/>\n      This is too vague and tautological — it just says finance is about finance.</p>\n      <p><strong>✅ Good Answer (1 mark):</strong><br/>\n      <em>\"The finance function produces cash-flow forecasts.\"</em><br/>\n      This is specific and names a real task the finance function performs.</p>\n      <p><strong>⚠️ Examiner Warning:</strong> Do NOT say \"the finance function is important for the business\" — this tells the examiner nothing. State a specific role: budgeting, calculating break-even, measuring profit and loss, sourcing finance, forecasting cash flow.</p>\n    ", "question": "What is the key rule for answering a 1-mark ''Identify'' or ''State'' question?", "options": ["Give a short paragraph explaining the point in full detail", "Give one vague general statement summarising the whole topic", "Give one clear, specific point with no explanation needed", "Give two or three related points to maximise your chances"]}'::jsonb, '{"answer": 2, "explain": "The card explains a 1-mark question needs exactly one clear, specific point — a vague or general statement, or unnecessary explanation, will not gain the mark."}'::jsonb),
('business:5-1-role-of-finance-function:tips:d18b7647', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The Holy Trinity: Understand → Apply → Analyse", "reading": "\n      <p>A 3-mark analyse question requires three distinct steps. Miss any one of them and you cap your marks at 2. Miss understanding and you score <strong>zero</strong> — even if your other points are excellent.</p>\n\n      <p><strong>Step 1 — Understanding (U): What does the finance function actually do?</strong><br/>\n      Name and briefly explain a specific finance task. Do NOT just repeat words from the question.</p>\n      <p><em>Starter: \"The finance function [produces/calculates/forecasts]...\"</em></p>\n\n      <p><strong>Step 2 — Application (APP): Link it to the specific business in the case study.</strong><br/>\n      Quote or directly reference information from the text — name the business, use a figure, reference a specific detail.</p>\n      <p><em>Starter: \"In the case of [Business Name], which [detail from text]...\"</em></p>\n\n      <p><strong>Step 3 — Analysis (AN): What is the impact on the business?</strong><br/>\n      Explain the effect on costs, revenue, profit, cash flow, or the ability to meet objectives.</p>\n      <p><em>Starter: \"This means that [Business Name] will be able to... / As a result, the business can...\"</em></p>\n\n      <p><strong>✅ Model Answer (BP question):</strong><br/>\n      \"The finance function produces budgets (U) in order to provide accurate financial information for BP''s managers to make informed decisions about possible partnerships (U), when developing wind farms (APP). This means BP can allocate the correct level of funding to renewable energy investments without putting the wider business at financial risk (AN).\"</p>\n\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Many students write everything they know about the finance function without linking it to BP. The examiner''s report noted that the majority of candidates scored zero on Q2 because they did not explain what the finance function involves — they just said it \"manages the business efficiently.\"</p>\n    ", "question": "What are the three steps required in a 3-mark ''Analyse'' answer?", "options": ["Definition, Evaluation, then a final and fully justified overall judgement", "Understanding, Application, then Analysis of the impact on the business", "Identification, Description, then a relevant real-world worked example", "Introduction, Summary, then a concluding recommendation paragraph"]}'::jsonb, '{"answer": 1, "explain": "The card sets out the ''Holy Trinity'' for analyse questions: Understanding (what the finance function does), Application (link to the case study), and Analysis (the impact)."}'::jsonb),
('business:5-1-role-of-finance-function:tips:5156e72e', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 7 marks — Argue Both Sides, Then Commit to a Justified Judgement", "reading": "\n      <p>A 7-mark evaluate question rewards four things: Knowledge, Application, Analysis (two separate points), and Evaluation (a justified judgement). Structure your answer in four paragraphs:</p>\n\n      <p><strong>Paragraph 1 — Knowledge & Understanding (K + U):</strong><br/>\n      Define or explain the finance function and its role in general terms.<br/>\n      <em>Starter: \"The finance function is the department responsible for... It plays a key role in...\"</em></p>\n\n      <p><strong>Paragraph 2 — Analysis & Application Point 1 (AN + APP):</strong><br/>\n      Give a specific example of how the finance function supports the business in the case study. Explain the impact.<br/>\n      <em>Starter: \"For example, in the case of [Business Name], the finance function... This will result in...\"</em></p>\n\n      <p><strong>Paragraph 3 — Analysis & Application Point 2 (AN + APP):</strong><br/>\n      Give a second, different example. Use case study detail again.<br/>\n      <em>Starter: \"Furthermore, the finance function could also... Because the text states that [quote/detail]...\"</em></p>\n\n      <p><strong>Paragraph 4 — Evaluation (EVAL — 3 marks):</strong><br/>\n      Make a clear judgement (1 mark). Then justify it using case study context (up to 2 marks). Your conclusion must add something NEW — do not just repeat your analysis points.</p>\n      <ul>\n        <li><strong>Decision:</strong> \"Overall, I believe the finance function is vital to the future success of [Business]...\"</li>\n        <li><strong>Context:</strong> \"...because the business is facing [specific challenge from text]...\"</li>\n        <li><strong>Impact/Reasoning:</strong> \"...meaning that without accurate financial data, the business could [specific consequence], putting its long-term survival at risk.\"</li>\n      </ul>\n      <p><strong>⚠️ The \"It Depends\" Trap:</strong> Only use \"it depends\" if you then specify what it depends on and why. A conclusion that simply repeats your analysis scores zero evaluation marks.</p>\n    ", "question": "What must a strong evaluation paragraph do, beyond repeating the analysis points?", "options": ["Make a clear judgement and justify it with new reasoning from the case study", "List every possible advantage and disadvantage without choosing between them", "Restate the two earlier analysis points using slightly different wording", "Introduce a brand new topic that has not been discussed anywhere before"]}'::jsonb, '{"answer": 0, "explain": "The card warns that a conclusion which just repeats the analysis scores zero evaluation marks — the judgement must be justified with new reasoning tied to the case study."}'::jsonb),
('business:5-1-role-of-finance-function:tips:1466ba2e', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'tips', 'mcq', 1, '{"readingTitle": "The Understanding Mark — Critical Warning — You MUST Define the Finance Function Before Anything Else", "reading": "\n      <p>In analyse questions about the finance function, <strong>the understanding mark is the gateway mark</strong>. Without it, no further marks can be awarded — regardless of how well you apply or analyse.</p>\n      <p>The examiner''s report for Q2 (BP question) stated: <em>\"The majority of candidates gained no marks, as they did not identify what the finance function of a business involved.\"</em></p>\n      <p><strong>What counts as understanding?</strong> You must name a specific task the finance function carries out:</p>\n      <ul>\n        <li>✅ \"produces cash-flow forecasts\"</li>\n        <li>✅ \"calculates break-even output\"</li>\n        <li>✅ \"measures revenue and costs\"</li>\n        <li>✅ \"creates budgets to plan spending\"</li>\n        <li>✅ \"arranges sources of finance such as loans\"</li>\n        <li>❌ \"manages the business efficiently\" — too vague, tautological</li>\n        <li>❌ \"looks after the finances\" — just repeats the question</li>\n        <li>❌ \"decides what to spend money on\" — this is not a finance function</li>\n      </ul>\n      <p><strong>Rule of thumb:</strong> Could a student who had never studied business write your answer? If yes, it''s not showing understanding — it''s just common sense and will score zero.</p>\n    ", "question": "Why is the understanding mark described as the ''gateway mark'' in analyse questions?", "options": ["It is the only one of the marks that can be earned without reading the case study", "Without naming a specific finance task, no further marks can be awarded at all", "It is automatically awarded to every single student who attempts the question", "It is worth far more marks than the application and analysis points combined"]}'::jsonb, '{"answer": 1, "explain": "The examiner''s report cited in the card shows most candidates scored zero because they never identified a specific finance task — without that gateway mark, no further marks can follow."}'::jsonb),
