('business:5-1-role-of-finance-function:match:229f6b65', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Finance Function”?", "options": ["The money a business receives from selling its goods or services.", "The expenses involved in making and selling a product or service.", "What remains when total costs are subtracted from total revenue and the result is positive.", "The department within a larger business that manages money, produces financial information, and supports decision-making."]}'::jsonb, '{"answer": 3, "explain": "“Finance Function” means: The department within a larger business that manages money, produces financial information, and supports decision-making."}'::jsonb),
('business:5-1-role-of-finance-function:match:c73d9820', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Revenue”?", "options": ["The expenses involved in making and selling a product or service.", "What remains when total costs are subtracted from total revenue and the result is positive.", "When total costs exceed total revenue — the business spends more than it earns.", "The money a business receives from selling its goods or services."]}'::jsonb, '{"answer": 3, "explain": "“Revenue” means: The money a business receives from selling its goods or services."}'::jsonb),
('business:5-1-role-of-finance-function:match:1b0e8b69', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Costs”?", "options": ["What remains when total costs are subtracted from total revenue and the result is positive.", "The expenses involved in making and selling a product or service.", "When total costs exceed total revenue — the business spends more than it earns.", "The level of output at which total revenue equals total costs — no profit or loss is made."]}'::jsonb, '{"answer": 1, "explain": "“Costs” means: The expenses involved in making and selling a product or service."}'::jsonb),
('business:5-1-role-of-finance-function:match:0904d93d', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Profit”?", "options": ["When total costs exceed total revenue — the business spends more than it earns.", "What remains when total costs are subtracted from total revenue and the result is positive.", "The level of output at which total revenue equals total costs — no profit or loss is made.", "The movement of money into and out of a business over a period of time."]}'::jsonb, '{"answer": 1, "explain": "“Profit” means: What remains when total costs are subtracted from total revenue and the result is positive."}'::jsonb),
('business:5-1-role-of-finance-function:match:ec3df558', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Loss”?", "options": ["The level of output at which total revenue equals total costs — no profit or loss is made.", "The movement of money into and out of a business over a period of time.", "When total costs exceed total revenue — the business spends more than it earns.", "A prediction of the future inflows and outflows of money in a business, used to anticipate cash shortages."]}'::jsonb, '{"answer": 2, "explain": "“Loss” means: When total costs exceed total revenue — the business spends more than it earns."}'::jsonb),
('business:5-1-role-of-finance-function:match:8e48c6e1', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Break-Even”?", "options": ["The movement of money into and out of a business over a period of time.", "The level of output at which total revenue equals total costs — no profit or loss is made.", "A prediction of the future inflows and outflows of money in a business, used to anticipate cash shortages.", "The different ways a business can raise money, such as loans, savings, overdrafts, or share issues."]}'::jsonb, '{"answer": 1, "explain": "“Break-Even” means: The level of output at which total revenue equals total costs — no profit or loss is made."}'::jsonb),
('business:5-1-role-of-finance-function:match:23436af2', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Cash Flow”?", "options": ["The movement of money into and out of a business over a period of time.", "A prediction of the future inflows and outflows of money in a business, used to anticipate cash shortages.", "The different ways a business can raise money, such as loans, savings, overdrafts, or share issues.", "Data including profit, loss, cash flow, break-even, profit margin and average rate of return, used in business decision-making."]}'::jsonb, '{"answer": 0, "explain": "“Cash Flow” means: The movement of money into and out of a business over a period of time."}'::jsonb),
('business:5-1-role-of-finance-function:match:0c831e8f', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Cash-Flow Forecast”?", "options": ["A prediction of the future inflows and outflows of money in a business, used to anticipate cash shortages.", "The different ways a business can raise money, such as loans, savings, overdrafts, or share issues.", "Data including profit, loss, cash flow, break-even, profit margin and average rate of return, used in business decision-making.", "The way different departments within a business rely on each other to function effectively."]}'::jsonb, '{"answer": 0, "explain": "“Cash-Flow Forecast” means: A prediction of the future inflows and outflows of money in a business, used to anticipate cash shortages."}'::jsonb),
