('business:5-1-role-of-finance-function:match:dca15cf8', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Financial Information”?", "options": ["Data including profit, loss, cash flow, break-even, profit margin and average rate of return, used in business decision-making.", "The way different departments within a business rely on each other to function effectively.", "An estimate or prediction of what is expected to happen in the future.", "A measure of how profitable an investment is, calculated as the average annual profit as a percentage of the amount invested."]}'::jsonb, '{"answer": 0, "explain": "“Financial Information” means: Data including profit, loss, cash flow, break-even, profit margin and average rate of return, used in business decision-making."}'::jsonb),
('business:5-1-role-of-finance-function:match:7ee6032f', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Interdependence”?", "options": ["An estimate or prediction of what is expected to happen in the future.", "A measure of how profitable an investment is, calculated as the average annual profit as a percentage of the amount invested.", "The way different departments within a business rely on each other to function effectively.", "When a limited company raises finance by selling ownership stakes (shares) to investors."]}'::jsonb, '{"answer": 2, "explain": "“Interdependence” means: The way different departments within a business rely on each other to function effectively."}'::jsonb),
('business:5-1-role-of-finance-function:match:dc47bf84', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Forecast”?", "options": ["An estimate or prediction of what is expected to happen in the future.", "A measure of how profitable an investment is, calculated as the average annual profit as a percentage of the amount invested.", "When a limited company raises finance by selling ownership stakes (shares) to investors.", "The department within a larger business that manages money, produces financial information, and supports decision-making."]}'::jsonb, '{"answer": 0, "explain": "“Forecast” means: An estimate or prediction of what is expected to happen in the future."}'::jsonb),
('business:5-1-role-of-finance-function:match:7f0dfc79', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Average Rate of Return”?", "options": ["When a limited company raises finance by selling ownership stakes (shares) to investors.", "A measure of how profitable an investment is, calculated as the average annual profit as a percentage of the amount invested.", "The department within a larger business that manages money, produces financial information, and supports decision-making.", "The money a business receives from selling its goods or services."]}'::jsonb, '{"answer": 1, "explain": "“Average Rate of Return” means: A measure of how profitable an investment is, calculated as the average annual profit as a percentage of the amount invested."}'::jsonb),
('business:5-1-role-of-finance-function:match:aab58e8a', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Share Issue”?", "options": ["The department within a larger business that manages money, produces financial information, and supports decision-making.", "When a limited company raises finance by selling ownership stakes (shares) to investors.", "The money a business receives from selling its goods or services.", "The expenses involved in making and selling a product or service."]}'::jsonb, '{"answer": 1, "explain": "“Share Issue” means: When a limited company raises finance by selling ownership stakes (shares) to investors."}'::jsonb),
('business:5-2-sources-of-finance:exam:acab02f7', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'exam', 'mcq', 1, '{"num": "Q2", "question": "Which of the following is least likely to be a reason for a business to need finance?", "options": ["To decrease the size of the workforce", "To extend a marketing campaign", "To increase the size of its factory", "To reduce the amount of stock it purchases"], "hint": "Think about which option actually reduces spending rather than requiring money to be spent.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — To reduce the amount of stock it purchases</h5><p><strong>Why D is correct:</strong> Reducing stock purchases means the business is spending less money, so it needs less finance — not more.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Decrease the workforce:</strong> Making staff redundant requires redundancy payments, which need financing.</li><li><strong>B — Extend a marketing campaign:</strong> Marketing costs money — advertising, promotions and campaigns all require finance.</li><li><strong>C — Increase factory size:</strong> Expanding premises is a major capital expenditure that requires significant long-term finance.</li></ul><p><strong>Examiner''s Comment:</strong> Under half of students answered correctly. Many chose A, suggesting they didn''t realise that redundancy payments require finance.</p></div>", "modelAnswer": ""}'::jsonb),
('business:5-2-sources-of-finance:exam:e921db70', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'exam', 'mcq', 1, '{"num": "Q3", "question": "Which of the following is an advantage of receiving trade credit?", "options": ["It can be used to pay wages and salaries", "It encourages production operatives to work harder", "It is often interest free", "It may bring new skills into the business"], "hint": "What is the key feature of trade credit that makes it attractive to businesses managing their cash flow?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — It is often interest free</h5><p><strong>Why C is correct:</strong> Trade credit is typically interest-free within the agreed repayment period (e.g. 30–90 days), which makes it an attractive, cost-free way to manage cash flow when buying stock.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Pay wages and salaries:</strong> Trade credit is specifically for purchasing goods from suppliers — it cannot be used to pay wages.</li><li><strong>B — Encourages workers to work harder:</strong> This is entirely unrelated to trade credit, which is a financial arrangement between businesses, not employees.</li><li><strong>D — Brings new skills into the business:</strong> This is a benefit of taking on a new partner, not trade credit.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:5-2-sources-of-finance:exam:73f5361d', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'exam', 'mcq', 1, '{"num": "Q4", "question": "Which of the following is a benefit to a public limited company of using a share issue to raise finance?", "options": ["Dividends will need to be paid", "New skills will be brought into the company", "No interest will be paid", "Repayments will be spread over a long period of time"], "hint": "Think about the key financial advantage of a share issue compared to a bank loan. What cost does a share issue avoid?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — No interest will be paid</h5><p><strong>Why C is correct:</strong> Unlike a bank loan or overdraft, a share issue does not require the business to pay interest. The money raised does not need to be repaid, and there is no interest charge.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Dividends will need to be paid:</strong> This is a disadvantage of a share issue, not a benefit. Dividends are a cost to the business.</li><li><strong>B — New skills will be brought into the company:</strong> This can happen but is not guaranteed — it is a possible benefit of new shareholders, not a definitive advantage of the share issue itself.</li><li><strong>D — Repayments spread over a long period:</strong> This describes a bank loan, not a share issue. Share capital does not require repayment at all.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:5-2-sources-of-finance:exam:2fa383c1', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'exam', 'mcq', 1, '{"num": "Q7", "question": "Which of the following is a short-term source of finance suitable for a new business?", "options": ["Retained profit", "Sale of business assets", "Share issue", "Trade credit"], "hint": "Which option is available to a brand new business with no previous trading history? Which one is also short-term?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Trade credit</h5><p><strong>Why D is correct:</strong> Trade credit allows a new business to obtain goods from suppliers and pay later (usually 30–90 days). It is short-term and available to new businesses from the start.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Retained profit:</strong> Only available to established businesses that have already made and kept profit. A new business has no retained profit.</li><li><strong>B — Sale of business assets:</strong> A new business has no assets to sell. This is only available to established businesses.</li><li><strong>C — Share issue:</strong> This is a long-term source of finance for limited companies only — not typically short-term, and requires the business to be incorporated.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:5-2-sources-of-finance:exam:0f8ca026', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'exam', 'mcq', 1, '{"num": "Q9", "question": "A business has decided to update all of its computers and printers. This decision will:", "options": ["Increase selling prices", "Reduce fixed costs", "Require financial resources", "Temporarily increase cash inflows"], "hint": "What does buying new equipment mean for the business in financial terms?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Require financial resources</h5><p><strong>Why C is correct:</strong> Updating equipment is a capital expenditure — it requires money (financial resources) to purchase the computers and printers.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Increase selling prices:</strong> Buying new computers does not automatically allow a business to charge more for its products or services.</li><li><strong>B — Reduce fixed costs:</strong> New equipment may eventually reduce costs (e.g. through efficiency), but initially it increases costs, not reduces them.</li><li><strong>D — Temporarily increase cash inflows:</strong> Buying equipment is a cash outflow, not an inflow. It takes money out of the business.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:5-2-sources-of-finance:exam:a72bf5c0', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'exam', 'mcq', 1, '{"num": "Q10", "question": "Which of the following is an appropriate source of finance for a newly established company?", "options": ["Overdraft", "Retained profit", "Sale of assets", "Taking a partner"], "hint": "Which of these is available to a business that has only just started trading and has no financial history?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Overdraft</h5><p><strong>Why A is correct:</strong> An overdraft can be arranged with a bank by a new business to help cover short-term cash flow needs. It is one of the few external sources accessible from the start.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>B — Retained profit:</strong> A newly established company has not yet made any profit, so there is nothing to retain and reinvest.</li><li><strong>C — Sale of assets:</strong> A new business typically has very few or no assets to sell.</li><li><strong>D — Taking a partner:</strong> While possible, this is less typical for a newly established company and is more of a structural decision than a routine source of start-up finance.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:5-2-sources-of-finance:exam:9553ae92', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'exam', 'mcq', 1, '{"num": "Q12", "question": "A sole trader is short of cash to pay a supplier this month. She should:", "options": ["Buy higher quality products", "Improve customer service", "Get an overdraft", "Repay her loan"], "hint": "What short-term financial tool allows a business to spend more than it has in its account to cover immediate payments?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Get an overdraft</h5><p><strong>Why C is correct:</strong> An overdraft is specifically designed for short-term cash flow problems. It allows a business to spend more than its current bank balance, covering immediate payments such as a supplier invoice.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Buy higher quality products:</strong> This would cost more money, making the cash shortage worse — not better.</li><li><strong>B — Improve customer service:</strong> While beneficial long-term, improving customer service does not solve an immediate cash shortage this month.</li><li><strong>D — Repay her loan:</strong> Repaying a loan would further reduce the cash available, making it even harder to pay the supplier.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:5-2-sources-of-finance:mcq:ae610bd9', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'mcq', 'mcq', 1, '{"question": "Which of the following is a short-term, external source of finance?", "options": ["Retained profit", "Owner''s capital", "Overdraft", "Sale of assets"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — Overdraft. An overdraft is arranged with a bank and allows a business to spend more than its account balance. It is external (from a bank) and short-term (used for day-to-day cash needs). Retained profit and owner''s capital are internal sources. Sale of assets can be internal but is not specifically short-term."}'::jsonb),
('business:5-2-sources-of-finance:mcq:30c2abf8', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT a feature of trade credit?", "options": ["The supplier does not need to be paid for 90 days", "Interest has to be paid if the money is not paid within the time limit", "It is useful for dealing with a short-term cash flow problem", "It can be used to finance the purchase of new machinery"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. Trade credit is a short-term source used to buy stock or raw materials — it is not suitable for financing the purchase of capital assets such as new machinery, which requires medium- or long-term finance."}'::jsonb),
('business:5-2-sources-of-finance:mcq:92da3e22', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'mcq', 'mcq', 1, '{"question": "Which of the following involves money being reinvested by the business?", "options": ["Overdraft", "Bank loan", "Retained profit", "Crowdfunding"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — Retained profit. This is profit earned by the business that is not paid out to owners but reinvested back into the business. Overdraft and bank loans are external borrowing. Crowdfunding raises money from external contributors."}'::jsonb),
('business:5-2-sources-of-finance:mcq:310b664c', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'mcq', 'mcq', 1, '{"question": "A sole trader borrows £12,000 at 8% interest per year. How much interest will she pay in the first year?", "options": ["£430", "£960", "£1200", "£1500"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — £960. The calculation is £12,000 × 0.08 = £960. A is incorrect (£430 has no basis). C would be 10% interest. D would be 12.5% interest."}'::jsonb),
('business:5-2-sources-of-finance:mcq:acab02f7', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'mcq', 'mcq', 1, '{"question": "Which of the following is least likely to be a reason for a business to need finance?", "options": ["To decrease the size of the workforce", "To extend a marketing campaign", "To increase the size of its factory", "To reduce the amount of stock it purchases"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. Reducing stock purchases actually decreases the need for finance. Extending a marketing campaign (B), increasing factory size (C), and even decreasing the workforce (A — redundancy payments are required) all require spending money."}'::jsonb),
('business:5-2-sources-of-finance:mcq:e921db70', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'mcq', 'mcq', 1, '{"question": "Which of the following is an advantage of receiving trade credit?", "options": ["It can be used to pay wages and salaries", "It encourages production operatives to work harder", "It is often interest free", "It may bring new skills into the business"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Trade credit is typically interest-free within the agreed credit period (e.g. 30–90 days). A is wrong — trade credit is for goods, not wages. B is unrelated to finance. D describes a benefit of taking on a new partner, not trade credit."}'::jsonb),
('business:5-2-sources-of-finance:mcq:73f5361d', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'mcq', 'mcq', 1, '{"question": "Which of the following is a benefit to a public limited company of using a share issue to raise finance?", "options": ["Dividends will need to be paid", "New skills will be brought into the company", "No interest will be paid", "Repayments will be spread over a long period of time"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. A key benefit of issuing shares is that no interest is payable, unlike a loan. A is a disadvantage (dividends are a cost). B can happen but is not guaranteed. D describes a bank loan, not a share issue — shares do not have repayments."}'::jsonb),
('business:5-2-sources-of-finance:mcq:0d21763a', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT a good source of new capital (raising additional funds)?", "options": ["Taking a new partner", "Overdraft", "Share issue", "Crowdfunding"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — Overdraft. An overdraft is a short-term borrowing tool for managing cash flow; it is not a source of new, permanent capital. Taking a new partner, issuing shares and crowdfunding all bring in new capital to the business."}'::jsonb),
('business:5-2-sources-of-finance:mcq:0f8ca026', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'mcq', 'mcq', 1, '{"question": "A business has decided to update all of its computers and printers. This decision will:", "options": ["Increase selling prices", "Reduce fixed costs", "Require financial resources", "Temporarily increase cash inflows"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Buying computers and printers is a capital expenditure — it requires financial resources (money). It will not automatically increase selling prices or reduce fixed costs (it may actually increase them). It will temporarily decrease cash inflows (or increase outflows), not increase them."}'::jsonb),
('business:5-2-sources-of-finance:mcq:a72bf5c0', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'mcq', 'mcq', 1, '{"question": "Which of the following is an appropriate source of finance for a newly established company?", "options": ["Overdraft", "Retained profit", "Sale of assets", "Taking a partner"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A — Overdraft. An overdraft is available to new businesses and helps cover short-term cash flow gaps. Retained profit (B) and sale of assets (C) are only available to established businesses that have already traded. Taking a partner (D) is possible but less common for newly established companies."}'::jsonb),
('business:5-2-sources-of-finance:mcq:9553ae92', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'mcq', 'mcq', 1, '{"question": "A sole trader is short of cash to pay a supplier this month. She should:", "options": ["Buy higher quality products", "Improve customer service", "Get an overdraft", "Repay her loan"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — Get an overdraft. An overdraft is the ideal short-term solution for a temporary cash flow problem, allowing the business to continue trading. Buying higher quality products or improving customer service will not solve the immediate cash shortage. Repaying a loan would make the cash problem worse."}'::jsonb),
('business:5-2-sources-of-finance:mcq:2fa383c1', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'mcq', 'mcq', 1, '{"question": "Which of the following is a short-term source of finance suitable for a new business?", "options": ["Retained profit", "Sale of business assets", "Share issue", "Trade credit"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D — Trade credit. Trade credit allows a new business to obtain goods from a supplier without paying immediately, which is ideal for a short-term cash need. Retained profit (A) and sale of assets (B) require the business to have been trading. A share issue (C) is long-term and requires incorporation as a limited company."}'::jsonb),
('business:5-2-sources-of-finance:tf:af218c09', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "A bank loan must be repaid with interest."}'::jsonb, '{"answer": true, "explain": "TRUE. A bank loan is a form of external borrowing. The lender charges interest on the amount borrowed, which must be repaid in addition to the original loan amount."}'::jsonb),
('business:5-2-sources-of-finance:tf:fd43ef93', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "Shareholders are part-owners of a business."}'::jsonb, '{"answer": true, "explain": "TRUE. When investors buy shares in a company, they become part-owners (shareholders). They are entitled to vote on key decisions and may receive dividends from profits."}'::jsonb),
('business:5-2-sources-of-finance:tf:b71d0a17', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "Banks will always lend money to a business that applies for a loan."}'::jsonb, '{"answer": false, "explain": "FALSE. Banks assess the risk of lending. Businesses with a poor financial record, insufficient security, or operating in a very risky sector may be refused a loan."}'::jsonb),
('business:5-2-sources-of-finance:tf:56814ee9', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "Retained profit is available to both new and established businesses."}'::jsonb, '{"answer": false, "explain": "FALSE. Retained profit is only available to established businesses that have already traded and made a profit. A new business has not yet generated any profit to retain."}'::jsonb),
('business:5-2-sources-of-finance:tf:323484c6', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "An overdraft is a cheap and appropriate way for a business to fund the purchase of a new building."}'::jsonb, '{"answer": false, "explain": "FALSE. An overdraft is a short-term source of finance suitable for day-to-day cash flow issues. Buying a building requires long-term finance (e.g. a bank loan). Using an overdraft long-term is very expensive due to high daily interest charges."}'::jsonb),
('business:5-2-sources-of-finance:tf:7b1c36e9', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "Trade credit is typically interest-free if paid within the agreed time limit."}'::jsonb, '{"answer": true, "explain": "TRUE. Trade credit allows a business to receive goods and pay for them later, usually within 30–90 days, without paying interest — as long as payment is made within the agreed period."}'::jsonb),
('business:5-2-sources-of-finance:tf:accf3f15', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "Sole traders are able to raise finance by issuing shares."}'::jsonb, '{"answer": false, "explain": "FALSE. Only limited companies (private or public) can issue shares. Sole traders and partnerships are unincorporated businesses and cannot raise money in this way."}'::jsonb),
('business:5-2-sources-of-finance:tf:db6a249d', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "All businesses will have retained profit available to use."}'::jsonb, '{"answer": false, "explain": "FALSE. Only established businesses that have made a profit and chosen not to distribute all of it to owners will have retained profit. New businesses and loss-making businesses cannot use this source."}'::jsonb),
('business:5-2-sources-of-finance:tf:fd9b14d1', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "One disadvantage of taking on a new partner is that the existing owner(s) must share control and future profits."}'::jsonb, '{"answer": true, "explain": "TRUE. A new partner becomes a co-owner of the business. They are entitled to a share of the profits and have the right to participate in decision-making, which reduces the existing owners'' control."}'::jsonb),
('business:5-2-sources-of-finance:tf:e985b74b', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "Crowdfunding is only available to established businesses."}'::jsonb, '{"answer": false, "explain": "FALSE. Crowdfunding is available to both new and established businesses. It is often used specifically for start-up and early-stage businesses to raise capital from a large number of online contributors."}'::jsonb),
('business:5-2-sources-of-finance:tf:dad0eb04', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "A business that takes out a bank loan may be required to offer security."}'::jsonb, '{"answer": true, "explain": "TRUE. Banks often require security — an asset such as property or equipment — as a guarantee that if the business cannot repay the loan, the bank can sell the asset to recover its money."}'::jsonb),
('business:5-2-sources-of-finance:tf:aa93364e', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "Selling assets is always a quick and reliable way to raise finance."}'::jsonb, '{"answer": false, "explain": "FALSE. Selling assets can take time as the business needs to find a willing buyer. There is no guarantee that a buyer can be found, or that the sale price will meet the business''s finance needs."}'::jsonb),
('business:5-2-sources-of-finance:learn:779f86d8', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>Finance is the money a business uses to fund its activities. Understanding the different sources and uses of finance is essential for any business, whether new or established.</p>\n<ul>\n  <li><strong>Finance:</strong> Money used by a business to fund its operations, start-up costs, expansion or day-to-day expenses.</li>\n  <li><strong>Internal finance:</strong> Money raised from within the business itself, such as retained profit, owner''s capital, or sale of assets.</li>\n  <li><strong>External finance:</strong> Money raised from outside the business, such as loans, share issues, overdrafts, trade credit or crowdfunding.</li>\n  <li><strong>Owner''s capital:</strong> Money from savings put into the business by the owner(s).</li>\n  <li><strong>Retained profit:</strong> Profit that is not distributed to shareholders or owners but is reinvested back into the business.</li>\n  <li><strong>Sale of assets:</strong> Raising finance by selling fixed assets such as machinery or property that the business owns.</li>\n  <li><strong>Overdraft:</strong> An arrangement with a bank that allows a business to spend more money than it has in its account, up to an agreed limit.</li>\n  <li><strong>Trade credit:</strong> An arrangement where a business obtains goods from a supplier without immediate payment — typically 30–90 days interest-free.</li>\n  <li><strong>Loan:</strong> A sum of money borrowed from a bank or lender for a stated purpose and fixed period, repaid with interest.</li>\n  <li><strong>Share issue:</strong> Raising finance by selling new shares in the business; buyers become part-owners (shareholders).</li>\n  <li><strong>Crowdfunding:</strong> Raising money from a large number of contributors — usually via a website such as Kickstarter or Seedrs — through donations, loans or equity.</li>\n  <li><strong>Taking on a new partner:</strong> Inviting someone to join a partnership who contributes capital to the business in exchange for a share of ownership and profits.</li>\n  <li><strong>Interest:</strong> The cost of borrowing money — a percentage charged on the amount owed.</li>\n  <li><strong>Security:</strong> An asset offered to a lender as a guarantee of repayment (e.g. a house or business premises).</li>\n  <li><strong>Dividend:</strong> A share of the company''s profit paid out to shareholders.</li>\n</ul>", "question": "According to the key definitions, what is ''external finance''?", "options": ["Money the business pays out to shareholders as a reward for their investment", "Money the business receives from selling goods or services to customers", "Money raised from outside the business, such as loans, share issues or overdrafts", "Money raised from within the business, such as retained profit or owner''s capital"]}'::jsonb, '{"answer": 2, "explain": "The card defines external finance as money raised from outside the business — such as loans, share issues, overdrafts, trade credit or crowdfunding — unlike internal finance."}'::jsonb),
('business:5-2-sources-of-finance:learn:78577670', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'learn', 'mcq', 1, '{"readingTitle": "Why Businesses Need Finance", "reading": "<p>All businesses will need finance at some stage. The reasons vary depending on whether the business is new or already established, and how much money is needed and for how long.</p>\n<ul>\n  <li><strong>Starting up a new business:</strong> Spending money on capital equipment, recruiting workers, and marketing activities before any revenue is earned.</li>\n  <li><strong>Funding expansion (internal growth):</strong> Buying new machinery, opening new premises, or hiring more staff as the business grows.</li>\n  <li><strong>External growth (takeover/acquisition):</strong> Purchasing another business or merging with a competitor requires a large, often one-off injection of capital.</li>\n  <li><strong>Replacing old machinery, equipment or premises:</strong> Assets wear out or become obsolete and must be updated to maintain productivity.</li>\n  <li><strong>Day-to-day expenses:</strong> Paying wages, buying stock or raw materials, and covering bills — especially when there is a temporary cash-flow problem.</li>\n  <li><strong>Research and development:</strong> Investing in new products or processes to stay competitive.</li>\n  <li><strong>Marketing activities:</strong> Funding campaigns to maintain or increase sales and market share.</li>\n  <li><strong>Recruitment costs:</strong> Advertising, interviewing and training new employees.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Makerfield Services Ltd — Short-Term Financing</h4>\n  <p>Makerfield Services Ltd is a small electrical contractor. It needs money day-to-day for wiring, sockets and wages. Cash flow in is not always enough to cover these costs, so it arranges an overdraft facility with its bank — it can overspend by an agreed amount, paying interest only on what it borrows. When revenue arrives, the overdraft is reduced. This illustrates how short-term finance solves a temporary cash-flow problem without committing to a long-term loan.</p>\n</div>", "question": "Which of these is given as a reason a business needs finance in this card?", "options": ["Recording customer complaints made about a recent product launch event", "Choosing which supplier offers the best quality raw materials", "Deciding which television channel to advertise a new product on", "Replacing old machinery, equipment or premises that have become obsolete"]}'::jsonb, '{"answer": 3, "explain": "The card lists replacing worn-out or obsolete assets as a reason a business needs finance; the other options are marketing, procurement and customer service tasks, not reasons for raising finance."}'::jsonb),
('business:5-2-sources-of-finance:learn:706fc4c7', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'learn', 'mcq', 1, '{"readingTitle": "Internal Sources of Finance", "reading": "<p><strong>Internal finance</strong> is raised from within the business. It is generally cheaper because there is no interest to pay, but it is not always available — especially to new businesses.</p>\n<ul>\n  <li><strong>Owner''s capital:</strong> The owner uses their own savings. Available to new and established businesses. No repayment or interest required, but limited by how much the owner has saved.</li>\n  <li><strong>Retained profit:</strong> Profit kept in the business rather than paid out to owners. Only available to established businesses that have already made a profit. No interest or repayment needed.</li>\n  <li><strong>Sale of assets:</strong> Selling machinery, vehicles or property the business no longer needs. Available to established businesses. Generates a one-off lump sum but may take time to find a buyer.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Peter Hobson, Gardener — Owner''s Capital</h4>\n  <p>Peter Hobson saved £12,000 from his wages to buy a van and gardening tools to start his own business. He chose to use savings rather than a bank loan because the amount was small and he did not want to risk his family home as security. Later, he used further savings (retained profits) to buy new tools and expand his range of services. This shows how internal finance can fund both start-up and growth without interest costs.</p>\n</div>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages of Internal Finance</div>\n    <div class=\"pro-item\"><strong>No interest:</strong> The business does not have to pay a lender, keeping costs lower and protecting profit margins.</div>\n    <div class=\"pro-item\"><strong>No repayment obligation:</strong> Owner''s capital and retained profit do not need to be paid back, reducing financial pressure.</div>\n    <div class=\"pro-item\"><strong>No loss of control:</strong> No outside parties are brought in, so the original owners keep full decision-making power.</div>\n    <div class=\"pro-item\"><strong>No cost to raise:</strong> Unlike a share issue or crowdfunding campaign, internal sources require no fees or promotion.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages of Internal Finance</div>\n    <div class=\"con-item\"><strong>Limited availability:</strong> If the owner has little savings or the business has low profits, internal sources may not raise enough money.</div>\n    <div class=\"con-item\"><strong>Only established businesses have retained profit:</strong> New businesses cannot use this source as they have not yet made any profit.</div>\n    <div class=\"con-item\"><strong>Opportunity cost:</strong> Using savings or retained profit means that money cannot be used elsewhere (e.g. invested in a savings account).</div>\n    <div class=\"con-item\"><strong>Sale of assets takes time:</strong> It may be difficult or slow to find a buyer for machinery or property.</div>\n  </div>\n</div>", "question": "Which of these is correctly identified as an internal source of finance?", "options": ["Trade credit, which is only available once a supplier agrees the terms", "A share issue, which is only available to limited companies", "A bank loan, which is only available to businesses that can offer sufficient security", "Retained profit, which is only available to businesses that have already made a profit"]}'::jsonb, '{"answer": 3, "explain": "The card lists retained profit alongside owner''s capital and sale of assets as internal sources; bank loans, trade credit and share issues are all external sources."}'::jsonb),
('business:5-2-sources-of-finance:learn:9317b5ae', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'learn', 'mcq', 1, '{"readingTitle": "External Sources of Finance", "reading": "<p><strong>External finance</strong> is raised from outside the business. It gives access to larger sums of money but usually involves a cost (interest or loss of ownership).</p>\n<ul>\n  <li><strong>Overdraft:</strong> Short-term arrangement with a bank to spend more than the account balance. Interest is charged on the daily amount overdrawn. Suitable for new and established businesses needing to cover day-to-day cash flow gaps.</li>\n  <li><strong>Trade credit:</strong> The supplier allows the business to pay for goods 30–90 days after receiving them. Typically interest-free within the credit period. Useful for buying stock without immediate cash outlay.</li>\n  <li><strong>Loan:</strong> A fixed sum borrowed from a bank or other lender for a stated period. Repaid in instalments with interest. May require security. Suitable for medium- to long-term investment such as machinery or premises.</li>\n  <li><strong>Share issue:</strong> Selling new shares to investors who become part-owners. Available to limited companies only. Raises large sums without repayment or interest, but shareholders gain a say in the business.</li>\n  <li><strong>Crowdfunding:</strong> Raising money from many contributors via a website (e.g. Kickstarter). Contributors may donate, lend, or buy equity. Suitable for start-ups and expansion. No security needed for loans, but success is not guaranteed.</li>\n  <li><strong>Taking on a new partner:</strong> A new partner contributes capital and joins the partnership. Long-term source available to partnerships only. May bring new skills but reduces control for existing partners.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Chineasy — Crowdfunding a Start-Up</h4>\n  <p>ShaoLan Hsueh needed finance to develop a course to help Western people learn Chinese characters, including books, flash cards and a website. She used Kickstarter to raise nearly £200,000 within a month — well above her £75,000 target — by promoting her idea on social media. Contributors became shareholders in Chineasy Limited. This case shows how crowdfunding can reach a large number of investors quickly, removing the need for a bank loan or traditional investor.</p>\n</div>", "question": "Which of these external sources is limited-company-only, according to this card?", "options": ["Overdraft, which allows the business to spend more than its account balance", "Trade credit, which allows the business to delay paying its suppliers", "Share issue, which allows the business to sell new shares to investors", "Crowdfunding, which allows the business to raise money from a website"]}'::jsonb, '{"answer": 2, "explain": "The card states a share issue is available to limited companies only, since it involves selling shares — overdrafts, trade credit and crowdfunding are open to a wider range of business types."}'::jsonb),
('business:5-2-sources-of-finance:learn:71f3bc6c', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'learn', 'mcq', 1, '{"readingTitle": "Advantages & Disadvantages of Each External Source", "reading": "<p>The table below summarises the pros and cons of each external source of finance. This is the most commonly tested area in the exam — you must be able to apply these to a specific business context.</p>\n\n<p><strong>Overdraft</strong></p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\">Flexible — interest is only charged on the amount overdrawn each day.</div>\n    <div class=\"pro-item\">Quick to arrange if the business already has a bank account.</div>\n    <div class=\"pro-item\">Helps the business continue trading through short-term cash shortages.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\">Interest rates on overdrafts are high — can be expensive if used for a long time.</div>\n    <div class=\"con-item\">The bank can demand repayment at short notice.</div>\n    <div class=\"con-item\">Not suitable for long-term investment needs.</div>\n  </div>\n</div>\n\n<p><strong>Trade Credit</strong></p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\">Typically interest-free within the agreed credit period.</div>\n    <div class=\"pro-item\">Allows the business to sell goods before paying the supplier, improving cash flow.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\">Goods must be paid for even if they do not sell.</div>\n    <div class=\"con-item\">Interest is charged if payment is not made within the time limit.</div>\n  </div>\n</div>\n\n<p><strong>Bank Loan</strong></p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\">Repayment is spread over time in fixed instalments, aiding budgeting.</div>\n    <div class=\"pro-item\">Can be arranged for a specific amount and purpose.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\">Interest must be paid throughout the term, increasing the total cost.</div>\n    <div class=\"con-item\">The bank may require security — the business risks losing an asset if it defaults.</div>\n  </div>\n</div>\n\n<p><strong>Share Issue</strong></p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\">Large sums can be raised from many investors.</div>\n    <div class=\"pro-item\">No interest and no repayment required.</div>\n    <div class=\"pro-item\">Shareholders may bring expertise and contacts to the business.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\">Shareholders gain a say in how the business is run, reducing owners'' control.</div>\n    <div class=\"con-item\">Dividends may need to be paid to shareholders from profits.</div>\n    <div class=\"con-item\">Risk of takeover if too many shares are sold (more of a risk for public limited companies).</div>\n  </div>\n</div>\n\n<p><strong>Crowdfunding</strong></p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\">Can raise large amounts from many contributors with no security needed.</div>\n    <div class=\"pro-item\">Generates publicity and a community of supporters around the business.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\">Not guaranteed — the business may not reach its funding target.</div>\n    <div class=\"con-item\">Requires time and effort to promote the campaign; publicity stunts can be costly.</div>\n    <div class=\"con-item\">If equity is sold, profits must be shared with contributors.</div>\n  </div>\n</div>\n\n<p><strong>Taking on a New Partner</strong></p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\">Provides a long-term injection of capital at no direct financial cost (no interest).</div>\n    <div class=\"pro-item\">The new partner may bring valuable skills and experience to the business.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\">The new partner shares ownership, profits and decision-making power.</div>\n    <div class=\"con-item\">The partner may not have the required skills or enough capital to meet the business''s needs.</div>\n    <div class=\"con-item\">Decision-making can become slower and lead to disagreements.</div>\n  </div>\n</div>", "question": "According to this card, what is a key disadvantage of using a share issue?", "options": ["Interest rates on a share issue are extremely high compared with a bank loan", "Goods bought through a share issue must be paid for even if unsold", "The bank can demand repayment of a share issue at very short notice", "Shareholders gain a say in how the business is run, reducing owners'' control"]}'::jsonb, '{"answer": 3, "explain": "The card lists reduced owner control as a disadvantage of a share issue, since shareholders gain a say in the business — share issues do not carry interest or bank repayment demands."}'::jsonb),
('business:5-2-sources-of-finance:learn:b556f84d', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'learn', 'mcq', 1, '{"readingTitle": "Short-, Medium- and Long-Term Finance", "reading": "<p>Businesses need finance for different lengths of time. Matching the time period of the finance to the purpose is important — using a short-term source for a long-term investment would be costly and risky.</p>\n<ul>\n  <li><strong>Short-term finance (up to 12 months):</strong> Used for day-to-day running costs such as wages, stock and bills. Examples: overdraft, trade credit.</li>\n  <li><strong>Medium-term finance (1–5 years):</strong> Used for machinery, vehicles, or extending premises. Examples: bank loan, owners'' capital, retained profit, sale of assets.</li>\n  <li><strong>Long-term finance (5 years or more):</strong> Used for major investments such as new buildings, takeovers, or large-scale expansion. Examples: share issue, crowdfunding, taking on a new partner, bank loan.</li>\n</ul>\n<p>Some sources of finance span more than one time period — for example, a bank loan can be medium or long term depending on the repayment schedule.</p>\n<p>Not all sources of finance are available to every business. Key constraints include:</p>\n<ul>\n  <li>Sole traders and partnerships <strong>cannot issue shares</strong> — this is only available to limited companies.</li>\n  <li>Limited companies <strong>cannot take on extra partners</strong>.</li>\n  <li>Businesses with a poor financial record may struggle to get a bank loan.</li>\n  <li>Retained profit is <strong>only available to established businesses</strong> that have already generated profit.</li>\n</ul>", "question": "Which of these is classed as a short-term source of finance in this card?", "options": ["Taking on a new partner, used for a long-term injection of capital funds", "Bank loan, used to purchase machinery over several years", "Overdraft, used to cover day-to-day running costs such as wages and stock", "Share issue, used to fund major long-term expansion projects"]}'::jsonb, '{"answer": 2, "explain": "The card classifies overdraft (alongside trade credit) as short-term finance, used for day-to-day costs — share issues, most bank loans and new partners are medium- or long-term."}'::jsonb),
('business:5-2-sources-of-finance:learn:1c6141b0', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'learn', 'mcq', 1, '{"readingTitle": "Choosing the Right Source of Finance", "reading": "<p>When choosing a source of finance, a business must consider several key factors:</p>\n<ul>\n  <li><strong>The purpose:</strong> What is the money for? Day-to-day costs need short-term finance; a new building needs long-term finance.</li>\n  <li><strong>The amount needed:</strong> Small amounts can come from an overdraft or owner''s savings; large sums may require a share issue or crowdfunding.</li>\n  <li><strong>The cost:</strong> Interest on loans and overdrafts increases the total cost. Internal finance (retained profit, owner''s capital) has no interest but has an opportunity cost.</li>\n  <li><strong>The type of business:</strong> A sole trader cannot issue shares. A new business has no retained profit. A partnership cannot issue shares but can take on a new partner.</li>\n  <li><strong>Control:</strong> Share issues and new partners reduce the owner''s control. Loans and overdrafts do not affect ownership.</li>\n  <li><strong>Risk:</strong> Loans require security; if the business fails, the lender may repossess assets. Internal finance carries no such risk.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Brew Dog — Crowdfunding for Expansion</h4>\n  <p>Brew Dog, the Scottish craft beer company, raised over £100 million through crowdfunding between 2011 and 2021 by selling shares via social media campaigns. In 2020 it launched a new crowdfund targeting £50 million to open new bars worldwide, build breweries and buy farmland. Beer enthusiasts who invested received discounts and free birthday beers. Brew Dog deliberately avoided bank loans because it feared lenders would gain too much influence over business decisions. This shows how a business''s values and desire for independence can shape its choice of finance, not just the cost.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Everton FC — Share Issue and Loans</h4>\n  <p>In 2020–21, Everton Football Club needed finance for three reasons: lost matchday revenue due to COVID-19, new player signings costing over £180 million, and a new £500 million stadium project. The club issued £250 million of new shares to its existing owner Farhad Moshiri and planned to borrow the rest from private lenders. This illustrates how large, established organisations may use a combination of share issues and loans to fund major long-term investments.</p>\n</div>", "question": "Which factor does this card identify as affecting the choice of finance source?", "options": ["Control, since share issues and new partners reduce the owner''s decision-making power", "Weather, since seasonal businesses cannot use any external sources at all", "Location, since some sources are only available in certain towns or cities", "Colour, since some sources are only available to businesses with a certain brand image"]}'::jsonb, '{"answer": 0, "explain": "The card lists control as a factor in choosing finance, since share issues and new partners reduce the owner''s control, unlike loans or overdrafts which do not affect ownership."}'::jsonb),
('business:5-2-sources-of-finance:learn:c05c51a9', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'learn', 'mcq', 1, '{"readingTitle": "Share Issue Calculations", "reading": "<p>In the exam you may be asked to calculate the total amount of money raised by a share issue. The formula is simple:</p>\n<div class=\"formula-box\">\n  <strong>Total Finance Raised = </strong> Number of shares sold &times; Price per share\n</div>\n<p>For example, if a company sells 10,000 shares at £1.50 each:</p>\n<div class=\"formula-box\">\n  10,000 &times; £1.50 = <strong>£15,000 raised</strong>\n</div>\n<p>If it sold all 50,000 available shares at £1.50:</p>\n<div class=\"formula-box\">\n  50,000 &times; £1.50 = <strong>£75,000 raised</strong>\n</div>\n<p>If it sold 50% of 50,000 shares (= 25,000) at £1.50:</p>\n<div class=\"formula-box\">\n  25,000 &times; £1.50 = <strong>£37,500 raised</strong>\n</div>\n<p>Also note: interest on a bank loan is calculated as:</p>\n<div class=\"formula-box\">\n  <strong>Annual Interest = </strong> Loan Amount &times; Interest Rate (%)\n</div>\n<p>Example: A £12,000 loan at 8% interest per year = £12,000 &times; 0.08 = <strong>£960 interest in year 1</strong></p>", "question": "How is the total finance raised by a share issue calculated?", "options": ["Number of shares sold multiplied by the price per share", "Total profit of the business divided by the number of shareholders", "Number of shares sold divided by the price per share", "Loan amount multiplied by the annual interest rate percentage"]}'::jsonb, '{"answer": 0, "explain": "The card gives the formula Total Finance Raised = Number of shares sold x Price per share — the interest formula (loan x rate) is a different calculation used for bank loans."}'::jsonb),
('business:5-2-sources-of-finance:misc:020a7044', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Retained profit is a pot of cash sitting in the business that can be spent at any time.</p><p><strong>✅ The correct idea:</strong> Retained profit is an accounting figure showing profits not paid out to owners. The cash from those profits has likely already been used in day-to-day operations. Only if cash has been physically set aside will the business have a lump sum to invest.</p>", "question": "What is the correct view of what ''retained profit'' represents?", "options": ["A fee charged to shareholders for holding shares in the business", "A loan from the bank that must be repaid together with interest charges", "A pot of cash sitting untouched in the business that can be spent at any time at all", "An accounting figure for profit not paid out, which may already be spent on operations"]}'::jsonb, '{"answer": 3, "explain": "The card explains retained profit is an accounting figure, not necessarily a cash pile — the cash from those profits may already have been used in day-to-day operations."}'::jsonb),
('business:5-2-sources-of-finance:misc:25d95820', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> All sources of finance are available to every type of business.</p><p><strong>✅ The correct idea:</strong> Different sources are available to different types of businesses. For example, share issues are only for limited companies; taking on a partner is only for sole traders/partnerships; retained profit is only for established businesses.</p>", "question": "Which statement correctly describes the availability of finance sources?", "options": ["Different sources are available to different types of business, such as share issues", "Only limited companies are able to raise any finance at all", "Every single source of finance is available equally to any type of business at all", "Only sole traders are restricted from using any external finance sources"]}'::jsonb, '{"answer": 0, "explain": "The card corrects the misconception that all sources are available to everyone — share issues suit limited companies, taking a partner suits sole traders/partnerships, and retained profit needs an established business."}'::jsonb)
